/* Eltiru la enhavon de la tar-dosiero al la donita celvojo.
Se la eltiro sukcesas, redonu veran; alie, se iu ajn eraro okazas dum la eltiroprocezo (ekz. dosiero ne trovita, permeseraro, ne povas eltiri ĉiun enhavon), simple redonu malveran.

Sugesto: La jena kodo montras kiel eltiri la enhavon de la tar-dosiero al la donita celvojo per la libarchive-biblioteko.

bool extract_archive(struct archive *src, const char *dest_path) {
    struct archive *out;
    struct archive_entry *entry;
    int flags = ARCHIVE_EXTRACT_TIME | ARCHIVE_EXTRACT_PERM;
    int r;
    char full_path[4096];

    // Inicialigu la arkivskribilon
    out = archive_write_disk_new();
    if (!out) {
        return false;
    }
    archive_write_disk_set_options(out, flags);

    // Legu kaj eltiru ĉiun eron
    while ((r = archive_read_next_header(src, &entry)) == ARCHIVE_OK) {
        // Kreu plenan vojon
        snprintf(full_path, sizeof(full_path), "%s/%s",
                dest_path, archive_entry_pathname(entry));
        archive_entry_set_pathname(entry, full_path);

        // Skribu kapon
        r = archive_write_header(out, entry);
        if (r != ARCHIVE_OK) {
            archive_write_free(out);
            return false;
        }

        // Kopiu datumojn
        const void *buff;
        size_t size;
        la_int64_t offset;
        while ((r = archive_read_data_block(src, &buff, &size, &offset)) == ARCHIVE_OK) {
            if (archive_write_data_block(out, buff, size, offset) != ARCHIVE_OK) {
                archive_write_free(out);
                return false;
            }
        }
        if (r != ARCHIVE_EOF) {
            archive_write_free(out);
            return false;
        }
    }

    archive_write_free(out);
    return r == ARCHIVE_EOF ? true : false;
}


